#define AHEAP_CAP 9072
#define LM_CAP_BYTES 36288
#define AHEAP_PHYS 1048576
#define LMEM_CAP 8388608
static int64_t AHEAP[AHEAP_PHYS];
static unsigned char LMEM[LMEM_CAP];
static int64_t AHP=0;
static int64_t LM_HP=0;
static int64_t lm_anew(int64_t n){if(n<0)n=0; if(LM_HP+4+8*n>LM_CAP_BYTES||AHP+1+n>AHEAP_CAP){fflush(stdout); exit(0);} LM_HP+=4+8*n; int64_t h=AHP; AHEAP[h]=n; for(int64_t i=0;i<n;i++)AHEAP[h+1+i]=0; AHP=AHP+1+n; return h;}
static int64_t lm_aget(int64_t a,int64_t i){int64_t len=AHEAP[a]; if(i<0||i>=len)return 0; return AHEAP[a+1+i];}
static void lm_aset(int64_t a,int64_t i,int64_t x){int64_t len=AHEAP[a]; if(i<0||i>=len)return; AHEAP[a+1+i]=x;}
static int64_t lm_alen(int64_t a){return AHEAP[a];}
static int64_t lm_alloc_bytes(int64_t num_bytes) {
  int64_t words = (num_bytes + 7) / 8;
  if (AHP + words > AHEAP_PHYS) { fflush(stdout); exit(0); }
  LM_HP += num_bytes;
  int64_t h = AHP;
  for (int64_t i = 0; i < words; i++) AHEAP[h + i] = 0;
  AHP += words;
  return (int64_t)&AHEAP[h];
}
static int64_t lm_alloc_sum(int64_t tag, int64_t payload) {
  if (LM_HP + 16 > LM_CAP_BYTES || AHP + 2 > AHEAP_CAP) { fflush(stdout); exit(0); }
  LM_HP += 16;
  int64_t h = AHP;
  AHEAP[h] = tag;
  AHEAP[h+1] = payload;
  AHP += 2;
  return (int64_t)&AHEAP[h];
}
static int64_t lm_concat(int64_t pa, int64_t pb) {
  int32_t la = *(int32_t*)pa;
  int32_t lb = *(int32_t*)pb;
  int64_t ptr = lm_alloc_bytes(4 + la + lb);
  *(int32_t*)ptr = la + lb;
  memcpy((char*)ptr + 4, (char*)pa + 4, la);
  memcpy((char*)ptr + 4 + la, (char*)pb + 4, lb);
  return ptr;
}
static int64_t lm_int2text(int64_t val_s) {
  uint64_t v = (uint64_t)val_s;
  int32_t neg = 0;
  if (val_s < 0) {
    neg = 1;
    v = 0 - v;
  }
  int32_t nd = 1;
  uint64_t tmp = v;
  while (1) {
    tmp = tmp / 10;
    if (tmp == 0) break;
    nd++;
  }
  int32_t len = nd + neg;
  int64_t ptr = lm_alloc_bytes(4 + len);
  *(int32_t*)ptr = len;
  char* w = (char*)ptr + 4 + len;
  uint64_t curr = v;
  while (1) {
    w--;
    *w = (char)(48 + (curr % 10));
    curr = curr / 10;
    if (curr == 0) break;
  }
  if (neg) {
    *((char*)ptr + 4) = '-';
  }
  return ptr;
}
static int64_t lm_texteq(int64_t pa, int64_t pb) {
  if (pa == pb) return 1;
  if (!pa || !pb) return 0;
  int32_t la = *(int32_t*)pa;
  int32_t lb = *(int32_t*)pb;
  if (la != lb) return 0;
  return memcmp((char*)pa + 4, (char*)pb + 4, la) == 0 ? 1 : 0;
}
static void lm_printtext(int64_t a) {
  if (!a) return;
  int32_t len = *(int32_t*)a;
  fwrite((char*)a + 4, 1, len, stdout);
}
